html:
{% set emp = frappe.db.get_value(
    "UOT Employees",
    doc.employee,
    ["employee_full_name", "employee_department_or_division"],
    as_dict=True
) %}

{% set dept_name = frappe.db.get_value(
    "UOT Departments",
    emp.employee_department_or_division,
    "department_name"
) %}

{% set leave_type_arabic = frappe.db.get_value(
    "UOT Leave Type",
    doc.leave_type,
    "leave_type"
) %}

{% set status_map = {
    'Pending': 'قيد الانتظار',
    'Approved': 'موافق عليه',
    'Rejected': 'مرفوض',
    'approved by the line manager': 'موافقة المدير المباشر',
    'Approved by the Administrative Associate': 'موافقة المعاون الإداري'
} %}

<!DOCTYPE html>
<html dir="rtl" lang="ar">
<head>
    <meta charset="UTF-8">
    <meta http-equiv="Content-Type" content="text/html; charset=utf-8"/>
    <style>

        @page {
            size: A4;
            margin: 0cm 0cm;
            transform: scale(0.9);
        }
        body {
        zoom: 0.85; /* 85% of original size */
        }

        /* ── Header ── */
        .header {
            width: 100%;
            margin-bottom: 20px;
        }

        .header-top {
            background: #1a3a6b;
            color: white;
            padding: 15px 20px;
            border-radius: 8px 8px 0 0;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .header-top .university-info {
            text-align: right;
        }

        .header-top .university-name {
            font-size: 16pt;
            font-weight: bold;
            letter-spacing: 1px;
        }

        .header-top .university-sub {
            font-size: 10pt;
            opacity: 0.85;
            margin-top: 3px;
        }

        .header-top .doc-info {
            text-align: left;
            font-size: 10pt;
            opacity: 0.85;
        }

        .header-top .doc-number {
            font-size: 13pt;
            font-weight: bold;
            margin-bottom: 3px;
        }

        .header-bottom {
            background: #f0f4ff;
            border: 1px solid #1a3a6b;
            border-top: none;
            border-radius: 0 0 8px 8px;
            padding: 8px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .header-bottom .form-title {
            font-size: 13pt;
            font-weight: bold;
            color: #1a3a6b;
        }

        .header-bottom .status-badge {
            padding: 4px 15px;
            border-radius: 20px;
            font-size: 11pt;
            font-weight: bold;
        }

        .status-pending  { background: #fff3cd; color: #856404; border: 1px solid #f0d080; }
        .status-approved { background: #d1e7dd; color: #0a3622; border: 1px solid #a3cfbb; }
        .status-rejected { background: #f8d7da; color: #842029; border: 1px solid #f1aeb5; }
        .status-other    { background: #cfe2ff; color: #084298; border: 1px solid #9ec5fe; }

        /* ── Section Title ── */
        .section-title {
            font-size: 12pt;
            font-weight: bold;
            color: white;
            background: #1a3a6b;
            padding: 6px 12px;
            border-radius: 4px;
            margin: 15px 0 8px 0;
        }

        /* ── Info Grid ── */
        .info-grid {
            width: 100%;
            border-collapse: collapse;
            border: 1px solid #dde3f0;
            border-radius: 6px;
            overflow: hidden;
        }

        .info-grid tr {
            border-bottom: 1px solid #eef0f8;
        }

        .info-grid tr:last-child {
            border-bottom: none;
        }

        .info-grid tr:nth-child(even) {
            background: #f8f9ff;
        }

        .info-grid td {
            padding: 9px 15px;
            font-size: 11pt;
            vertical-align: middle;
        }

        .info-grid .label {
            font-weight: bold;
            color: #444;
            width: 30%;
            border-left: 2px solid #dde3f0;
        }

        .info-grid .value {
            color: #1a1a1a;
        }

        .info-grid .label-2 {
            font-weight: bold;
            color: #444;
            width: 20%;
            border-left: 2px solid #dde3f0;
            border-right: 2px solid #dde3f0;
        }

        /* ── Leave Details Box ── */
        .leave-details {
            width: 100%;
            border-collapse: collapse;
            margin: 8px 0;
        }

        .leave-details td {
            padding: 0 5px;
            vertical-align: top;
        }

        .detail-card {
            border: 1px solid #dde3f0;
            border-radius: 6px;
            padding: 12px;
            background: #f8f9ff;
            text-align: center;
        }

        .detail-card .card-label {
            font-size: 10pt;
            color: #888;
            margin-bottom: 5px;
        }

        .detail-card .card-value {
            font-size: 13pt;
            font-weight: bold;
            color: #1a3a6b;
        }

        /* ── Reason Box ── */
        .reason-box {
            border: 1px solid #dde3f0;
            border-radius: 6px;
            padding: 12px 15px;
            background: #fafbff;
            min-height: 60px;
            font-size: 11pt;
            line-height: 1.8;
            color: #333;
        }

        /* ── Timeline ── */
        .timeline {
            width: 100%;
            border-collapse: collapse;
            border: 1px solid #dde3f0;
        }

        .timeline th {
            background: #f0f4ff;
            color: #1a3a6b;
            font-size: 10pt;
            padding: 7px 12px;
            border-bottom: 2px solid #dde3f0;
            font-weight: bold;
        }

        .timeline td {
            padding: 8px 12px;
            font-size: 10pt;
            border-bottom: 1px solid #eef0f8;
            vertical-align: middle;
        }

        .timeline tr:last-child td {
            border-bottom: none;
        }

        .timeline tr:nth-child(even) td {
            background: #f8f9ff;
        }

        /* ── Signatures ── */
        .signatures {
            width: 100%;
            border-collapse: collapse;
            margin-top: 10px;
        }

        .signatures td {
            padding: 10px;
            text-align: center;
            vertical-align: top;
            width: 25%;
        }

        .sig-box {
            border: 1px solid #dde3f0;
            border-radius: 6px;
            padding: 10px;
            background: #f8f9ff;
        }

        .sig-title {
            font-size: 10pt;
            font-weight: bold;
            color: #1a3a6b;
            margin-bottom: 8px;
            padding-bottom: 5px;
            border-bottom: 1px solid #dde3f0;
        }

        .sig-line {
            border-bottom: 1px dotted #999;
            margin: 25px 10px 8px 10px;
            height: 1px;
        }

        .sig-label {
            font-size: 9pt;
            color: #888;
        }

        /* ── Footer ── */
        .footer {
            margin-top: 20px;
            padding-top: 10px;
            border-top: 2px solid #1a3a6b;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .footer .footer-right {
            font-size: 9pt;
            color: #888;
        }

        .footer .footer-left {
            font-size: 9pt;
            color: #888;
            text-align: left;
        }

        .confidential {
            text-align: center;
            font-size: 9pt;
            color: #aaa;
            margin-top: 5px;
            letter-spacing: 2px;
        }

        /* ── Watermark for status ── */
        .watermark {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%) rotate(-35deg);
            font-size: 80pt;
            font-weight: bold;
            opacity: 0.04;
            color: #1a3a6b;
            pointer-events: none;
            white-space: nowrap;
            z-index: 0;
        }
    </style>
</head>
<body>

<!-- Watermark -->
{% if doc.workflow_state == 'Approved' %}
<div class="watermark">موافق عليه</div>
{% elif doc.workflow_state == 'Rejected' %}
<div class="watermark">مرفوض</div>
{% endif %}

<!-- Header -->
<div class="header">
    <div class="header-top">
        <div class="university-info">
            <div style = "color: white;" class="university-name">الجامعة التكنولوجية</div>
            <div style = "color: white;" class="university-sub">نظام إدارة الموارد البشرية — {{ dept_name or '' }}</div>
        </div>
        <div style = "color: white;" class="doc-info">
            <div style = "color: white;" class="doc-number">{{ doc.name }}</div>
            <div style = "color: white;">
                {% if doc.creation %}
                    {% if doc.creation is string %}
                        {{ doc.creation.split(' ')[0].replace('-', '/') }}
                    {% else %}
                        {{ doc.creation.strftime('%Y/%m/%d') }}
                    {% endif %}
                {% endif %}
            </div>
        </div>
    </div>
    <div class="header-bottom">
        <div class="form-title">استمارة طلب إجازة</div>
        <div>
            {% set state = doc.workflow_state or 'Pending' %}
            {% if state == 'Approved' %}
                <span class="status-badge status-approved">{{ status_map.get(state, state) }}</span>
            {% elif state == 'Rejected' %}
                <span class="status-badge status-rejected">{{ status_map.get(state, state) }}</span>
            {% elif state == 'Pending' %}
                <span class="status-badge status-pending">{{ status_map.get(state, state) }}</span>
            {% else %}
                <span class="status-badge status-other">{{ status_map.get(state, state) }}</span>
            {% endif %}
        </div>
    </div>
</div>

<!-- Employee Information -->
<div class="section-title">أولاً: معلومات الموظف</div>
<table class="info-grid">
    <tr>
        <td class="label">الاسم الكامل</td>
        <td class="value">{{ doc.data_lprk }}</td>
        <td class="label-2">الرقم الوظيفي</td>
        <td class="value">{{ doc.employee }}</td>
    </tr>
    <tr>
        <td class="label">القسم / الشعبة</td>
        <td class="value" colspan="3">{{ dept_name or '' }}</td>
    </tr>
</table>

<!-- Leave Details -->
<div class="section-title">ثانياً: تفاصيل الإجازة</div>
<table class="leave-details">
    <tr>
        <td style="width:25%">
            <div class="detail-card">
                <div class="card-label">نوع الإجازة</div>
                <div class="card-value" style="font-size:11pt;">
                    {{ leave_type_arabic or doc.leave_type }}
                </div>
            </div>
        </td>
        <td style="width:25%">
            <div class="detail-card">
                <div class="card-label">تاريخ البداية</div>
                <div class="card-value">{{ doc.from_day }}</div>
            </div>
        </td>
        <td style="width:25%">
            <div class="detail-card">
                <div class="card-label">تاريخ النهاية</div>
                <div class="card-value">{{ doc.to_day }}</div>
            </div>
        </td>
        <td style="width:25%">
            <div class="detail-card">
                <div class="card-label">عدد الأيام</div>
                <div class="card-value" style="font-size:18pt;">
                    {{ doc.days_count_of_leave }}
                    <span style="font-size:10pt; color:#888;">يوم</span>
                </div>
            </div>
        </td>
    </tr>
</table>

<!-- Reason -->
<div class="section-title">ثالثاً: سبب الإجازة</div>
<div class="reason-box">
    {{ doc.reason_for_leave or 'لم يتم ذكر سبب' }}
</div>

<!-- Approval Timeline -->
<div class="section-title">رابعاً: مسار الموافقة</div>
<table class="timeline">
    <tr>
        <th>المرحلة</th>
        <th>الحالة</th>
        <th>التاريخ</th>
        <th>ملاحظات</th>
    </tr>
    <tr>
        <td>تقديم الطلب</td>
        <td>
            <span style="color:#0a3622; font-weight:bold;">
                ✓ تم التقديم
            </span>
        </td>
        <td>
            {% if doc.creation %}
                {% if doc.creation is string %}
                    {{ doc.creation.split(' ')[0].replace('-', '/') }}
                {% else %}
                    {{ doc.creation.strftime('%Y/%m/%d') }}
                {% endif %}
            {% endif %}
        </td>
        <td>—</td>
    </tr>
    <tr>
        <td>موافقة المدير المباشر</td>
        <td>
            {% if doc.workflow_state in ['approved by the line manager', 'Approved by the Administrative Associate', 'Approved'] %}
                <span style="color:#0a3622; font-weight:bold;">✓ موافق</span>
            {% elif doc.workflow_state == 'Rejected' %}
                <span style="color:#842029; font-weight:bold;">✗ مرفوض</span>
            {% else %}
                <span style="color:#856404;">⏳ قيد الانتظار</span>
            {% endif %}
        </td>
        <td>—</td>
        <td>—</td>
    </tr>
    <tr>
        <td>موافقة المعاون الإداري</td>
        <td>
            {% if doc.workflow_state in ['Approved by the Administrative Associate', 'Approved'] %}
                <span style="color:#0a3622; font-weight:bold;">✓ موافق</span>
            {% elif doc.workflow_state == 'Rejected' %}
                <span style="color:#842029; font-weight:bold;">✗ مرفوض</span>
            {% else %}
                <span style="color:#856404;">⏳ قيد الانتظار</span>
            {% endif %}
        </td>
        <td>—</td>
        <td>—</td>
    </tr>
    <tr>
        <td>القرار النهائي</td>
        <td>
            {% if doc.workflow_state == 'Approved' %}
                <span style="color:#0a3622; font-weight:bold;">✓ موافق عليه</span>
            {% elif doc.workflow_state == 'Rejected' %}
                <span style="color:#842029; font-weight:bold;">✗ مرفوض</span>
            {% else %}
                <span style="color:#856404;">⏳ قيد الانتظار</span>
            {% endif %}
        </td>
        <td>—</td>
        <td>—</td>
    </tr>
</table>

<!-- Signatures -->
<div class="section-title">خامساً: التوقيعات</div>
<table class="signatures">
    <tr>
        <td>
            <div class="sig-box">
                <div class="sig-title">توقيع الموظف</div>
                <div class="sig-line"></div>
                <div class="sig-label">الاسم والتوقيع</div>
            </div>
        </td>
        <td>
            <div class="sig-box">
                <div class="sig-title">المدير المباشر</div>
                <div class="sig-line"></div>
                <div class="sig-label">الاسم والتوقيع</div>
            </div>
        </td>
        <td>
            <div class="sig-box">
                <div class="sig-title">المعاون الإداري</div>
                <div class="sig-line"></div>
                <div class="sig-label">الاسم والتوقيع</div>
            </div>
        </td>
        <td>
            <div class="sig-box">
                <div class="sig-title">مدير الموارد البشرية</div>
                <div class="sig-line"></div>
                <div class="sig-label">الاسم والتوقيع</div>
            </div>
        </td>
    </tr>
</table>

<!-- Footer -->
<div class="footer">
    <div class="footer-right">
        نظام إدارة الموارد البشرية — الجامعة التكنولوجية - كلية الهندسة الميكانيكية
    </div>
    <div class="footer-left">
        {{ doc.name }} |
        {% if doc.creation %}
            {% if doc.creation is string %}
                {{ doc.creation.split(' ')[0].replace('-', '/') }}
            {% else %}
                {{ doc.creation.strftime('%Y/%m/%d') }}
            {% endif %}
        {% endif %}
    </div>
</div>
<div class="confidential">— وثيقة رسمية — للاستخدام الداخلي فقط —</div>

</body>
</html>
